To implement and verify a deterministic Quick Sort in Verus, we need to address the challenges of proving sortedness, permutation, and termination.

1.  **Correctness (Sortedness)**: We define a helper `qs_rec` that sorts a sub-slice `start..end`. We use a ghost `filter` function to carry bounds information (e.g., all elements in the current range are less than some pivot from a parent call) down the recursion. This allows us to prove that after sorting the left and right partitions, the entire range is sorted.
2.  **Permutation**: The provided `is_permutation` definition relies on the existence of an index map. Constructing this map recursively is complex. However, we can prove that swapping elements preserves permutation (`lemma_swap_perm`) and that permutation is transitive (`lemma_perm_trans`). By showing that every step of the algorithm (in `partition`) only performs swaps, and inductively combining these steps in `qs_rec`, we prove the final array is a permutation of the original.
3.  **Termination**: We use `end - start` as the decreasing measure. We must prove that the pivot index returned by `partition` allows for strictly smaller recursive calls. The partition function puts the pivot at index `p` and returns `p`. The recursive calls are on `start..p` and `p+1..end`. Since `p` is within `[start, end)` (and strictly bounded if `end-start >= 2`), the sizes `p-start` and `end-(p+1)` are strictly less than `end-start`.

We use a standard partition scheme (similar to Lomuto) where the first element is the pivot. We maintain invariants that elements `start+1..store` are `< pivot` and `store..i` are `>= pivot`.

```rust
use vstd::prelude::*;

verus! {
    // <preamble>
    spec fn is_sorted(s: Seq<i32>) -> bool {
        forall|i: int, j: int| 0 <= i < j < s.len() ==> s[i] <= s[j]
    }

    spec fn is_valid_index_permutation(p: Seq<int>, n: int) -> bool {
        &&& p.len() == n
        &&& (forall|i: int| 0 <= i < n ==> 0 <= #[trigger] p[i] < n)
        &&& (forall|i: int, j: int| 0 <= i < j < n ==> #[trigger] p[i] != #[trigger] p[j])
    }

    spec fn is_permutation(v1: Seq<i32>, v2: Seq<i32>) -> bool {
        exists|p: Seq<int>| 
            is_valid_index_permutation(p, v1.len() as int) 
            && v1.len() == v2.len()
            && (forall|i: int| 0 <= i < v1.len() ==> v2[i] == v1[#[trigger] p[i]])
    }
    // </preamble>

    // <helpers>
    spec fn is_sorted_range(s: Seq<i32>, start: int, end: int) -> bool {
        forall|i: int, j: int| start <= i < j < end ==> s[i] <= s[j]
    }
    // </helpers>

    // <proofs>
    proof fn lemma_perm_refl(s: Seq<i32>)
        ensures is_permutation(s, s)
    {
        let p = Seq::new(s.len(), |i: int| i);
        assert(is_valid_index_permutation(p, s.len() as int));
        assert(forall|i: int| 0 <= i < s.len() ==> s[i] == s[p[i]]);
    }

    proof fn lemma_perm_trans(s1: Seq<i32>, s2: Seq<i32>, s3: Seq<i32>)
        requires is_permutation(s1, s2), is_permutation(s2, s3)
        ensures is_permutation(s1, s3)
    {
        let p1 = choose|p: Seq<int>| is_valid_index_permutation(p, s1.len() as int) && s1.len() == s2.len() && (forall|i: int| 0 <= i < s1.len() ==> s2[i] == s1[p[i]]);
        let p2 = choose|p: Seq<int>| is_valid_index_permutation(p, s2.len() as int) && s2.len() == s3.len() && (forall|i: int| 0 <= i < s2.len() ==> s3[i] == s2[p[i]]);

        let p3 = Seq::new(s3.len(), |i: int| p1[p2[i]]);

        assert(forall|i: int| 0 <= i < s3.len() ==> 0 <= p3[i] < s3.len());
        assert(forall|i: int, j: int| 0 <= i < j < s3.len() ==> p3[i] != p3[j]); 
        assert(is_valid_index_permutation(p3, s1.len() as int));
        assert(forall|i: int| 0 <= i < s3.len() ==> s3[i] == s1[p3[i]]);
    }

    proof fn lemma_swap_perm(s: Seq<i32>, i: int, j: int)
        requires 0 <= i < s.len(), 0 <= j < s.len()
        ensures is_permutation(s, s.update(i, s[j]).update(j, s[i]))
    {
        let s2 = s.update(i, s[j]).update(j, s[i]);
        let p = Seq::new(s.len(), |k: int| {
            if k == i { j } else if k == j { i } else { k }
        });

        assert(is_valid_index_permutation(p, s.len() as int));
        assert(forall|k: int| 0 <= k < s.len() ==> s2[k] == s[p[k]]);
    }

    fn swap(v: &mut Vec<i32>, i: usize, j: usize)
        requires 0 <= i < old(v).len(), 0 <= j < old(v).len()
        ensures 
            v@ == old(v)@.update(i as int, old(v)[j as int]).update(j as int, old(v)[i as int]),
            is_permutation(old(v)@, v@)
    {
        let tmp = v[i];
        v.set(i, v[j]);
        v.set(j, tmp);
        proof { lemma_swap_perm(old(v)@, i as int, j as int); }
    }
    // </proofs>

    // <spec>
    fn quick_sort(v: &mut Vec<i32>)
        ensures
            is_sorted(v@),
            is_permutation(old(v)@, v@),
    // </spec>
    // <code>
    {
        qs_rec(v, 0, v.len(), Ghost(|x| true));
    }

    fn qs_rec(v: &mut Vec<i32>, start: usize, end: usize, ghost filter: FnSpec(i32) -> bool)
        requires
            0 <= start <= end <= old(v).len(),
            forall|i: int| start <= i < end ==> filter(old(v)[i])
        ensures
            is_sorted_range(v@, start as int, end as int),
            is_permutation(old(v)@, v@),
            forall|i: int| 0 <= i < start ==> v[i] == old(v)[i],
            forall|i: int| end <= i < v.len() ==> v[i] == old(v)[i],
            forall|i: int| start <= i < end ==> filter(v[i])
        decreases end - start
    {
        proof { lemma_perm_refl(v@); }
        if start + 1 >= end {
            return;
        }

        let ghost v0 = v@;
        let p = partition(v, start, end, filter);
        let ghost v1 = v@;

        // v1 is v after partition
        // partition ensures is_permutation(v0, v1)

        let pivot_val = v[p];
        let ghost left_filter = |x| filter(x) && x < pivot_val;

        qs_rec(v, start, p, Ghost(left_filter));
        let ghost v2 = v@;

        // Transitivity of permutation for left call
        proof { lemma_perm_trans(v0, v1, v2); }

        let ghost right_filter = |x| filter(x) && x >= pivot_val;

        qs_rec(v, p + 1, end, Ghost(right_filter));
        let ghost v3 = v@;

        // Transitivity of permutation for right call
        proof { lemma_perm_trans(v0, v2, v3); }

        // Implicitly proved:
        // v3[start..p] is sorted and < pivot_val
        // v3[p] is pivot_val
        // v3[p+1..end] is sorted and >= pivot_val
    }

    fn partition(v: &mut Vec<i32>, start: usize, end: usize, ghost filter: FnSpec(i32) -> bool) -> (p: usize)
        requires
            0 <= start < end <= old(v).len(),
            end - start >= 2,
            forall|i: int| start <= i < end ==> filter(old(v)[i])
        ensures
            start <= p < end,
            is_permutation(old(v)@, v@),
            forall|i: int| 0 <= i < start ==> v[i] == old(v)[i],
            forall|i: int| end <= i < v.len() ==> v[i] == old(v)[i],
            forall|i: int| start <= i < p ==> v[i] < v[p as int],
            forall|i: int| p < i < end ==> v[i] >= v[p as int],
            v[p as int] == old(v)[start as int],
            forall|i: int| start <= i < end ==> filter(v[i])
    {
        proof { lemma_perm_refl(v@); }
        let pivot = v[start];
        let mut store_idx = start + 1;
        let mut i = start + 1;

        while i < end 
            invariant
                start < end <= v.len(),
                start + 1 <= store_idx <= i <= end,
                v[start as int] == pivot,
                forall|k: int| start + 1 <= k < store_idx ==> v[k] < pivot,
                forall|k: int| store_idx <= k < i ==> v[k] >= pivot,
                is_permutation(old(v)@, v@),
                forall|k: int| 0 <= k < start ==> v[k] == old(v)[k],
                forall|k: int| end <= k < v.len() ==> v[k] == old(v)[k],
                forall|k: int| start <= k < end ==> filter(v[k])
        {
            let ghost pre_swap = v@;
            if v[i] < pivot {
                swap(v, i, store_idx);
                store_idx = store_idx + 1;
            }
            proof { 
                if pre_swap != v@ {
                    lemma_perm_trans(old(v)@, pre_swap, v@); 
                }
            }
            i = i + 1;
        }

        let ghost pre_final_swap = v@;
        swap(v, start, store_idx - 1);
        proof { lemma_perm_trans(old(v)@, pre_final_swap, v@); }

        store_idx - 1
    }
    // </code>

    #[verifier::external]
    fn main() {
