To verify the deterministic Quick Sort in Verus, we define a stronger permutation property `is_bounded_perm` which asserts that a permutation only affects elements within a specific range `[start, end)`. This allows us to prove that recursive calls do not disturb the elements outside their working range, and combined with the fact that `partition` splits elements based on the pivot, we can deduce global sortedness.

We define `is_bounded_perm` using `exists|p|` where `p` is an index map that is identity outside `[start, end)`. We provide lemmas to show that `swap` generates a bounded permutation, and that bounded permutations are transitive and preserve the bounds (i.e., elements remain within `[start, end)`). We also use a lemma `lemma_bounded_perm_preserves_lt` (and `_ge`) to show that if a range consists of elements smaller than a pivot, permuting it maintains that property. This avoids the need for passing complex ghost filters or closures.

```rust
use vstd::prelude::*;

verus! {
    // <preamble>
    spec fn is_sorted(s: Seq<i32>) -> bool {
        forall|i: int, j: int| 0 <= i < j < s.len() ==> s[i] <= s[j]
    }

    spec fn is_valid_index_permutation(p: Seq<int>, n: int) -> bool {
        &&& p.len() == n
        &&& (forall|i: int| 0 <= i < n ==> 0 <= #[trigger] p[i] < n)
        &&& (forall|i: int, j: int| 0 <= i < j < n ==> #[trigger] p[i] != #[trigger] p[j])
    }

    spec fn is_permutation(v1: Seq<i32>, v2: Seq<i32>) -> bool {
        exists|p: Seq<int>| 
            is_valid_index_permutation(p, v1.len() as int) 
            && v1.len() == v2.len()
            && (forall|i: int| 0 <= i < v1.len() ==> v2[i] == v1[#[trigger] p[i]])
    }
    // </preamble>

    // <helpers>
    spec fn is_sorted_range(s: Seq<i32>, start: int, end: int) -> bool {
        forall|i: int, j: int| start <= i < j < end ==> s[i] <= s[j]
    }

    spec fn is_perm_with_map(v1: Seq<i32>, v2: Seq<i32>, p: Seq<int>) -> bool {
        &&& is_valid_index_permutation(p, v1.len() as int)
        &&& v1.len() == v2.len()
        &&& (forall|i: int| 0 <= i < v1.len() ==> v2[i] == v1[p[i]])
    }

    spec fn is_bounded_perm(v1: Seq<i32>, v2: Seq<i32>, start: int, end: int) -> bool {
        exists|p: Seq<int>| 
            is_perm_with_map(v1, v2, p)
            && (forall|i: int| 0 <= i < v1.len() && (i < start || i >= end) ==> p[i] == i)
    }
    // </helpers>

    // <proofs>
    proof fn lemma_bounded_perm_implies_range_map(v1: Seq<i32>, v2: Seq<i32>, start: int, end: int, p: Seq<int>)
        requires 
            is_perm_with_map(v1, v2, p),
            forall|i: int| 0 <= i < v1.len() && (i < start || i >= end) ==> p[i] == i,
            0 <= start <= end <= v1.len()
        ensures
            forall|i: int| start <= i < end ==> start <= p[i] < end
    {
        if exists|i: int| start <= i < end && !(start <= p[i] < end) {
            let i = choose|i: int| start <= i < end && !(start <= p[i] < end);
            let j = p[i]; 
            // j is outside [start, end)
            // p[j] == j because j is outside
            // p[i] == j == p[j]
            // i == j (injectivity)
            // contradiction: i in range, j out range
        }
    }

    proof fn lemma_bounded_perm_preserves_lt(v1: Seq<i32>, v2: Seq<i32>, start: int, end: int, pivot: i32)
        requires 
            is_bounded_perm(v1, v2, start, end),
            0 <= start <= end <= v1.len(),
            forall|i: int| start <= i < end ==> v1[i] < pivot
        ensures
            forall|i: int| start <= i < end ==> v2[i] < pivot
    {
        let p = choose|p: Seq<int>| is_perm_with_map(v1, v2, p) && (forall|i: int| 0 <= i < v1.len() && (i < start || i >= end) ==> p[i] == i);
        lemma_bounded_perm_implies_range_map(v1, v2, start, end, p);
    }

    proof fn lemma_bounded_perm_preserves_ge(v1: Seq<i32>, v2: Seq<i32>, start: int, end: int, pivot: i32)
        requires 
            is_bounded_perm(v1, v2, start, end),
            0 <= start <= end <= v1.len(),
            forall|i: int| start <= i < end ==> v1[i] >= pivot
        ensures
            forall|i: int| start <= i < end ==> v2[i] >= pivot
    {
        let p = choose|p: Seq<int>| is_perm_with_map(v1, v2, p) && (forall|i: int| 0 <= i < v1.len() && (i < start || i >= end) ==> p[i] == i);
        lemma_bounded_perm_implies_range_map(v1, v2, start, end, p);
    }

    proof fn lemma_swap_is_bounded(s: Seq<i32>, i: int, j: int, start: int, end: int)
        requires 
            0 <= start <= i < end, start <= j < end,
            end <= s.len()
        ensures
            is_bounded_perm(s, s.update(i, s[j]).update(j, s[i]), start, end)
