        &&& is_valid_index_permutation(p, v1.len() as int)
        &&& v1.len() == v2.len()
        &&& (forall|i: int| 0 <= i < v1.len() ==> v2[i] == v1[#[trigger] p[i]])
    }

    spec fn is_bounded_perm(v1: Seq<i32>, v2: Seq<i32>, start: int, end: int) -> bool {
        exists|p: Seq<int>| 
            is_perm_with_map(v1, v2, p)
            && (forall|i: int| 0 <= i < v1.len() && (i < start || i >= end) ==> p[i] == i)
    }
    // </helpers>

    // <proofs>
    proof fn lemma_bounded_perm_implies_range_map(v1: Seq<i32>, v2: Seq<i32>, start: int, end: int, p: Seq<int>)
        requires 
            is_perm_with_map(v1, v2, p),
            forall|i: int| 0 <= i < v1.len() && (i < start || i >= end) ==> p[i] == i,
            0 <= start <= end <= v1.len()
        ensures
            forall|i: int| start <= i < end ==> start <= #[trigger] p[i] < end
    {
        assert(forall|i: int| start <= i < end ==> start <= #[trigger] p[i] < end) by {
             if exists|i: int| start <= i < end && !(start <= #[trigger] p[i] < end) {
                let i = choose|i: int| start <= i < end && !(start <= #[trigger] p[i] < end);
                let j = p[i];
                // j must be outside [start, end)
                assert(j < start || j >= end);
                assert(p[j] == j); // By assumption
                // p[i] == j == p[j]. Injectivity => i == j.
                // Contradiction.
             }
        }
    }

    proof fn lemma_bounded_perm_preserves_lt(v1: Seq<i32>, v2: Seq<i32>, start: int, end: int, pivot: i32)
        requires 
            is_bounded_perm(v1, v2, start, end),
            0 <= start <= end <= v1.len(),
            forall|i: int| start <= i < end ==> #[trigger] v1[i] < pivot
        ensures
            forall|i: int| start <= i < end ==> v2[i] < pivot
    {
        let p = choose|p: Seq<int>| is_perm_with_map(v1, v2, p) && (forall|i: int| 0 <= i < v1.len() && (i < start || i >= end) ==> p[i] == i);
        lemma_bounded_perm_implies_range_map(v1, v2, start, end, p);
    }

    proof fn lemma_bounded_perm_preserves_ge(v1: Seq<i32>, v2: Seq<i32>, start: int, end: int, pivot: i32)
        requires 
            is_bounded_perm(v1, v2, start, end),
            0 <= start <= end <= v1.len(),
            forall|i: int| start <= i < end ==> #[trigger] v1[i] >= pivot
        ensures
            forall|i: int| start <= i < end ==> v2[i] >= pivot
    {
        let p = choose|p: Seq<int>| is_perm_with_map(v1, v2, p) && (forall|i: int| 0 <= i < v1.len() && (i < start || i >= end) ==> p[i] == i);
        lemma_bounded_perm_implies_range_map(v1, v2, start, end, p);
    }

    proof fn lemma_bounded_perm_identity_outside(v1: Seq<i32>, v2: Seq<i32>, start: int, end: int)
        requires 
            is_bounded_perm(v1, v2, start, end),
            0 <= start <= end <= v1.len()
        ensures
            forall|i: int| 0 <= i < v1.len() && (i < start || i >= end) ==> v2[i] == v1[i]
    {
        let p = choose|p: Seq<int>| is_perm_with_map(v1, v2, p) && (forall|i: int| 0 <= i < v1.len() && (i < start || i >= end) ==> p[i] == i);
    }

    proof fn lemma_swap_is_bounded(s: Seq<i32>, i: int, j: int, start: int, end: int)
        requires 
            0 <= start <= i < end, start <= j < end,
            end <= s.len()
        ensures
            is_bounded_perm(s, s.update(i, s[j]).update(j, s[i]), start, end)
    {
        let s2 = s.update(i, s[j]).update(j, s[i]);
        let p = Seq::new(s.len(), |k: int| {
            if k == i { j } else if k == j { i } else { k }
        });
        assert(is_valid_index_permutation(p, s.len() as int));
        assert(forall|k: int| 0 <= k < s.len() ==> s2[k] == s[p[k]]);
        assert(is_perm_with_map(s, s2, p));
        assert(forall|k: int| 0 <= k < s.len() && (k < start || k >= end) ==> p[k] == k);
    }

    proof fn lemma_refl_bounded(s: Seq<i32>, start: int, end: int)
        requires 0 <= s.len()
        ensures is_bounded_perm(s, s, start, end)
    {
        let p = Seq::new(s.len(), |i: int| i);
        assert(is_perm_with_map(s, s, p));
    }

    proof fn lemma_trans_bounded(v1: Seq<i32>, v2: Seq<i32>, v3: Seq<i32>, start: int, end: int)
        requires is_bounded_perm(v1, v2, start, end), is_bounded_perm(v2, v3, start, end)
        ensures is_bounded_perm(v1, v3, start, end)
    {
        let p1 = choose|p: Seq<int>| is_perm_with_map(v1, v2, p) && (forall|i: int| 0 <= i < v1.len() && (i < start || i >= end) ==> p[i] == i);
        let p2 = choose|p: Seq<int>| is_perm_with_map(v2, v3, p) && (forall|i: int| 0 <= i < v2.len() && (i < start || i >= end) ==> p[i] == i);
        let p3 = Seq::new(v3.len(), |i: int| p1[p2[i]]);

        assert(forall|i: int, j: int| 0 <= i < j < v3.len() ==> p3[i] != p3[j]); 
        assert(is_perm_with_map(v1, v3, p3));
        assert(forall|i: int| 0 <= i < v3.len() && (i < start || i >= end) ==> p3[i] == i);
    }

    proof fn lemma_weaken_bounded(v1: Seq<i32>, v2: Seq<i32>, start_sub: int, end_sub: int, start: int, end: int)
        requires 
            is_bounded_perm(v1, v2, start_sub, end_sub),
            start <= start_sub <= end_sub <= end
        ensures is_bounded_perm(v1, v2, start, end)
    {
        let p = choose|p: Seq<int>| is_perm_with_map(v1, v2, p) && (forall|i: int| 0 <= i < v1.len() && (i < start_sub || i >= end_sub) ==> p[i] == i);
    }

    proof fn lemma_bounded_is_perm(v1: Seq<i32>, v2: Seq<i32>, start: int, end: int)
        requires is_bounded_perm(v1, v2, start, end)
        ensures is_permutation(v1, v2)
    {
        let p = choose|p: Seq<int>| is_perm_with_map(v1, v2, p);
    }

    fn swap(v: &mut Vec<i32>, i: usize, j: usize)
        requires 0 <= i < old(v).len(), 0 <= j < old(v).len()
        ensures v@ == old(v)@.update(i as int, old(v)[j as int]).update(j as int, old(v)[i as int])
    {
        let tmp = v[i];
        v.set(i, v[j]);
        v.set(j, tmp);
    }

    fn qs_rec(v: &mut Vec<i32>, start: usize, end: usize)
        requires
            0 <= start <= end <= old(v).len()
        ensures
            is_sorted_range(v@, start as int, end as int),
            is_bounded_perm(old(v)@, v@, start as int, end as int)
        decreases end - start
    {
        proof { lemma_refl_bounded(v@, start as int, end as int); }
        if start >= end || start + 1 >= end {
            return;
        }

        let ghost v0 = v@;
        let p = partition(v, start, end);
        let ghost v1 = v@;

        let pivot_val = v[p];

        qs_rec(v, start, p);
        let ghost v2 = v@;

        proof {
            lemma_weaken_bounded(v1, v2, start as int, p as int, start as int, end as int); 
            lemma_trans_bounded(v0, v1, v2, start as int, end as int);
            lemma_bounded_perm_identity_outside(v1, v2, start as int, p as int);
            lemma_bounded_perm_preserves_lt(v1, v2, start as int, p as int, pivot_val);
        }

        qs_rec(v, p + 1, end);
        let ghost v3 = v@;

        proof {
            lemma_weaken_bounded(v2, v3, p + 1 as int, end as int, start as int, end as int);
            lemma_trans_bounded(v0, v2, v3, start as int, end as int);
            lemma_bounded_perm_identity_outside(v2, v3, p + 1 as int, end as int);
            lemma_bounded_perm_preserves_ge(v2, v3, p + 1 as int, end as int, pivot_val);
        }
    }

    fn partition(v: &mut Vec<i32>, start: usize, end: usize) -> (p: usize)
        requires
            0 <= start < end <= old(v).len(),
            end - start >= 2
        ensures
            start <= p < end,
            is_bounded_perm(old(v)@, v@, start as int, end as int),
            forall|i: int| start <= i < p ==> v[i] < v[p as int],
            forall|i: int| p < i < end ==> v[i] >= v[p as int],
            v[p as int] == old(v)[start as int]
    {
        proof { lemma_refl_bounded(v@, start as int, end as int); }
        let pivot = v[start];
        let mut store_idx = start + 1;
        let mut i = start + 1;

        while i < end 
            invariant
                start < end <= v.len(),
                start + 1 <= store_idx <= i <= end,
                v[start as int] == pivot,
                forall|k: int| start + 1 <= k < store_idx ==> v[k] < pivot,
                forall|k: int| store_idx <= k < i ==> v[k] >= pivot,
                is_bounded_perm(old(v)@, v@, start as int, end as int),
                forall|k: int| 0 <= k < start ==> v[k] == old(v)[k],
                forall|k: int| end <= k < v.len() ==> v[k] == old(v)[k]
            decreases end - i
        {
            let ghost pre_swap = v@;
            if v[i] < pivot {
                swap(v, i, store_idx);
                store_idx = store_idx + 1;
                proof { 
                    lemma_swap_is_bounded(pre_swap, i as int, (store_idx - 1) as int, start as int, end as int);
                    lemma_trans_bounded(old(v)@, pre_swap, v@, start as int, end as int);
                }
            }
            i = i + 1;
        }

        let ghost pre_final_swap = v@;
        swap(v, start, store_idx - 1);
        proof {
            lemma_swap_is_bounded(pre_final_swap, start as int, (store_idx - 1) as int, start as int, end as int);
            lemma_trans_bounded(old(v)@, pre_final_swap, v@, start as int, end as int);
        }

        store_idx - 1
    }

    fn quick_sort(v: &mut Vec<i32>)
        ensures
            is_sorted(v@),
            is_permutation(old(v)@, v@),
    {
        qs_rec(v, 0, v.len());
        proof { 
             lemma_bounded_is_perm(old(v)@, v@, 0, v.len() as int);
             assert(is_sorted_range(v@, 0, v.len() as int)); 
        }
    }

    #[verifier::external]
    fn main() {
        let mut v = vec![5, 1, 4, 2, 8];
        let ghost original_v = v@;

        quick_sort(&mut v);

        assert(is_sorted(v@));
        assert(is_permutation(original_v, v@));
    }
}
