        exists|p: Seq<int>| 
            is_perm_with_map(v1, v2, p)
            && (forall|i: int| 0 <= i < v1.len() && (i < start || i >= end) ==> p[i] == i)
    }
    // </helpers>

    // <proofs>
    proof fn lemma_bounded_perm_implies_range_map(v1: Seq<i32>, v2: Seq<i32>, start: int, end: int, p: Seq<int>)
        requires 
            is_perm_with_map(v1, v2, p),
            forall|i: int| 0 <= i < v1.len() && (i < start || i >= end) ==> p[i] == i,
