        let p = choose|p: Seq<int>| is_perm_with_map(v1, v2, p) && (forall|i: int| 0 <= i < v1.len() && (i < start || i >= end) ==> p[i] == i);
        assert(forall|i: int| 0 <= i < v1.len() && (i < start || i >= end) ==> v2[i] == v1[i]) by {
